INSERT INTO `questions` (`id`, `language_id`, `map_key`, `title`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `answer`, `task1`, `task2`, `created_at`, `updated_at`) VALUES
	(1, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'What is the primary purpose of the Dart programming language?', 'To create backend server applications only', 'To create frontend user interfaces for web and mobile apps', 'To manage database operations', 'To develop machine learning models', 'To create frontend user interfaces for web and mobile apps', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(2, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'Who developed the Dart programming language?', 'Microsoft', 'Google', 'Apple', 'Facebook', 'Google', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(3, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'In which year was Dart first developed?', '2009', '2011', '2013', '2015', '2011', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(4, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'What type of programming language is Dart?', 'Procedural programming language', 'Functional programming language', 'Object-oriented programming language', 'Logic-based programming language', 'Object-oriented programming language', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(5, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'Which of the following can Dart be used to build?', 'Only mobile applications', 'Only web applications', 'Server and desktop applications', 'Only embedded systems', 'Server and desktop applications', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(6, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'What kind of syntax does Dart use?', 'Python-style syntax', 'C-style syntax', 'Ruby-style syntax', 'Lisp-style syntax', 'C-style syntax', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(7, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'Which platform is NOT a primary target for Dart applications?', 'Web', 'Mobile', 'Desktop', 'Operating Systems', 'Operating Systems', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(8, 1, 'AubSeLi2nwNTUA-L3Kfn4', 'Basics of Dart', 'What is a key feature of Dart that makes it suitable for frontend development?', 'Low-level system programming', 'Support for UI component creation', 'Direct hardware access', 'Database query optimization', 'Support for UI component creation', 'Write a simple Dart program that prints \'Hello, Dart!\' to the console. Include the main function and use proper syntax.', 'Create a Dart program that defines a class called \'Person\' with properties for name and age, and a method to print a greeting message including the person\'s name and age.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(9, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'What is DartPad primarily used for?', 'Running full-scale Flutter applications', 'Writing and running Dart code snippets online', 'Managing Flutter project dependencies', 'Debugging complex server-side Dart code', 'Writing and running Dart code snippets online', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(10, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'What type of code can DartPad execute besides Dart?', 'Python', 'Flutter', 'Java', 'C++', 'Flutter', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(11, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'What is a key benefit of using DartPad?', 'It requires a full development environment setup', 'It allows testing Flutter apps without local setup', 'It provides direct database access', 'It supports multi-language compilation', 'It allows testing Flutter apps without local setup', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(12, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'Which of the following is NOT a feature of DartPad?', 'Running Flutter widgets', 'Syntax highlighting', 'Local file storage', 'Code sharing', 'Local file storage', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(13, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'How can you access DartPad?', 'Only through a desktop application', 'Via a web browser', 'Only within an IDE', 'Through a mobile app', 'Via a web browser', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(14, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'What is a common use case for DartPad?', 'Deploying production apps', 'Prototyping Flutter widgets', 'Running machine learning models', 'Managing server configurations', 'Prototyping Flutter widgets', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
