	(16, 1, 'vR38pAZOfI55R7N7NLY5N', 'Dart Pad', 'What does DartPad eliminate the need for when testing code?', 'Code editor', 'Full development environment setup', 'Internet connection', 'Version control system', 'Full development environment setup', 'Use DartPad to create a simple Dart program that calculates the square of a number and prints the result.', 'In DartPad, create a Flutter widget that displays a centered text with a custom background color and font size.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(17, 1, 'P-SbMLN-AaNMss_7X0_5N', 'Variables', 'How many types of variables are there in Flutter?', 'Two', 'Three', 'Four', 'Five', 'Three', 'Write a Dart program that declares a local variable to store a userâ€™s name and prints a greeting.', 'Create a Dart class with an instance variable for a counter and a method to increment it.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(18, 1, 'P-SbMLN-AaNMss_7X0_5N', 'Variables', 'Which of the following is NOT a type of variable in Flutter?', 'Local', 'Global', 'Instance', 'Static', 'Static', 'Write a Dart program that declares a local variable to store a userâ€™s name and prints a greeting.', 'Create a Dart class with an instance variable for a counter and a method to increment it.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
	(19, 1, 'P-SbMLN-AaNMss_7X0_5N', 'Variables', 'What is a key characteristic of a local variable in Flutter?', 'Accessible throughout the app', 'Defined within a function or block', 'Shared across all instances of a class', 'Stored in a database', 'Defined within a function or block', 'Write a Dart program that declares a local variable to store a userâ€™s name and prints a greeting.', 'Create a Dart class with an instance variable for a counter and a method to increment it.', '2025-08-29 02:04:18', '2025-08-29 02:04:18'),
