	(1360, 1, 'med4T8PVkxIo465VuKDEj', 'Package Managers', 'What is flutter pub upgrade?', 'Updates dependencies to latest versions', 'Installs new packages', 'Builds the app', 'Publishes a package', 'Updates dependencies to latest versions', 'Add a dependency to a Flutter project using pubspec.yaml.', 'Create and publish a simple package to pub.dev.', '2025-08-29 02:04:19', '2025-08-29 02:04:19'),
