INSERT INTO `units` (`id`, `language_id`, `name`, `external_id`, `description`, `sort_order`, `created_at`, `updated_at`) VALUES
	(1, 1, 'Dart Basics', 'AubSeLi2nwNTUA-L3Kfn4', '# Dart Basics\n\nDart is an open-source, general-purpose, object-oriented programming language with C-style syntax developed by Google in 2011. The purpose of Dart programming is to create a frontend user interfaces for the web and mobile apps. It can also be used to build server and desktop applications.\n\nVisit the following resources to learn more:\n\n- [@official@Dart Overview](https://dart.dev/overview)\n- [@video@What is Dart?](https://www.youtube.com/watch?v=sOSd6G1qXoY)\n- [@video@Dart in 100 Seconds](https://www.youtube.com/watch?v=NrO0CJCbYLA)\n- [@feed@Explore top posts about Dart](https://app.daily.dev/tags/dart?ref=roadmapsh)', 1, '2025-08-28 09:42:01', '2026-04-05 14:42:24'),
	(2, 1, 'Setup Development Environment', 'HCJXVgnglYuRhK0zl3iPG', '# Setup Development Environment\n\nTo set up a development environment for Flutter, you need to install the following software:\n\n*   Flutter SDK: Download and install the latest version of the Flutter SDK from the official website.\n*   Integrated Development Environment (IDE): You can use Android Studio, Visual Studio Code, IntelliJ IDEA or any other IDE of your choice.\n*   Emulator or a physical device: You can use an emulator or a physical device to run and test your Flutter apps. You can use the Android emulator provided by Android Studio or use a physical Android or iOS device.\n*   Git: Git is used for version control and is recommended for Flutter development. You can download and install Git.\n*   Dart SDK: Dart is the programming language used by Flutter, and the Dart SDK is required to develop Flutter apps. The Dart SDK is included in the Flutter SDK.\n\nOnce you have installed all the required software, you can create a new Flutter project using the Flutter CLI or your IDE, and start building your app.\n\nVisit the following resources to learn more:\n\n- [@official@Get Started with Flutter](https://docs.flutter.dev/get-started/install)\n- [@official@Installing Dart SDK](https://dart.dev/get-dart)', 2, '2025-08-28 09:42:01', '2026-04-05 14:42:24'),
	(3, 1, 'Widgets', 'dy2Jep9hIIECaLutx-3K0', '# Widgets\n\nWidgets in Flutter are the basic building blocks of the user interface. They define how the UI looks and behaves. Widgets can be combined to create complex user interfaces and can be easily customized. Widgets in Flutter are also designed to be highly reusable, allowing developers to build complex UIs quickly and efficiently.\n\nVisit the following resources to learn more:\n\n- [@official@Introduction to Widgets](https://docs.flutter.dev/development/ui/widgets-intro)\n- [@official@Widget Catalog](https://docs.flutter.dev/development/ui/widgets)\n- [@video@Flutter Widgets Explained](https://www.youtube.com/watch?v=FU2Eeizo95o)', 3, '2025-08-28 09:42:01', '2026-04-05 14:42:25'),
	(4, 1, 'Working With Assets', 'z50iixpcCMe9sTh-gwTI3', '# MongoDB Basics\n\nMongoDB is a popular NoSQL database that is designed to store and manage large volumes of unstructured or semi-structured data. Unlike traditional relational databases that use tables and rows, MongoDB employs a document-oriented data model, where data is stored in flexible, JSON-like documents called BSON (Binary JSON). This allows for a dynamic schema, meaning that documents within the same collection can have different structures, making it easier to adapt to changing data requirements. MongoDB supports rich query capabilities, including filtering, sorting, and aggregation, enabling developers to perform complex queries efficiently.\n\nVisit the following resources to learn more:\n\n- [@official@MongoDB](https://www.mongodb.com/)\n- [@official@What Is MongoDB?](https://www.mongodb.com/company/what-is-mongodb)\n- [@official@MongoDB Database Documentation](https://www.mongodb.com/docs/)\n', 4, '2025-08-28 09:42:01', '2026-04-05 14:42:25'),
	(5, 1, 'Version Control Systems', '2nz5JoAPsZftFNLypr3Is', '# Version Control Systems\n\nVersion control systems allow you to track changes to your codebase/files over time. They allow you to go back to some previous version of the codebase without any issues. Also, they help in collaborating with people working on the same code – if you’ve ever collaborated with other people on a project, you might already know the frustration of copying and merging the changes from someone else into your codebase; version control systems allow you to get rid of this issue.\n\nVisit the following resources to learn more:\n\n- [@article@What is Version Control? - GitHub](https://github.com/resources/articles/software-development/what-is-version-control)\n- [@article@What is Version Control? - Atlassian](https://www.atlassian.com/git/tutorials/what-is-version-control)\n- [@video@Version Control System Introduction](https://www.youtube.com/watch?v=zbKdDsNNOhg)\n- [@video@Git & GitHub Crash Course For Beginners](https://www.youtube.com/watch?v=SWYqp7iY_Tc)\n- [@video@Learn Git in 20 Minutes](https://youtu.be/Y9XZQO1n_7c?t=21)', 5, '2025-08-28 09:42:01', '2026-04-05 14:42:28'),
	(6, 1, 'Repo Hosting Services', 'qGN95GG0Q3dur72GS3EDX', '# Repo Hosting Services\n\nSeveral popular repository hosting services, including GitHub, GitLab, Bitbucket, AWS CodeCommit, and Azure DevOps, support Flutter development by offering Git repository management, issue tracking, and collaboration tools. When selecting a service, developers should consider factors like project needs, scalability, cost, ease of use, integrations, and third-party tool support to ensure the chosen platform aligns with their specific requirements.\n\nVisit the following resources to learn more:\n\n- [@official@GitHub](https://github.com/)\n- [@official@GitLab](https://gitlab.com/)\n- [@official@Azure](https://azure.microsoft.com/)\n- [@article@How to Deploy a Flutter Web App?](https://medium.com/solute-labs/flutter-for-web-how-to-deploy-a-flutter-web-app-c7d9db7ced2e)\n- [@article@Deploying - Flutter](https://docs.flutter.dev/deployment/web#deploying-to-the-web)\n- [@video@Host Flutter Website On GitHub Pages](https://www.youtube.com/watch?v=z-yOqoQ2q6s)', 6, '2025-08-28 09:42:01', '2026-04-05 14:42:29'),
	(7, 1, 'Design Principles', 'drwRSEnl1-ziCvxWJZMJ2', '# Design Principles\n\nFlutter development emphasizes design principles like Material Design, responsiveness, user-centeredness, simplicity, consistency, accessibility, and performance to create visually appealing and user-friendly applications that function seamlessly across various devices and cater to diverse user needs.\n\nVisit the following resources to learn more:\n\n- [@article@Design - Principles](https://docs.flutter.dev/cookbook/design)', 7, '2025-08-28 09:42:01', '2026-04-05 14:42:29'),
	(8, 1, 'Package Manager', 'med4T8PVkxIo465VuKDEj', '# Package Manager\n\nThe package manager for Flutter is called pub. It is used to manage Flutter projects\' dependencies and publish Flutter packages. It is included with the Flutter SDK and can be run from the command line using the `pub` command.\n\nVisit the following resources to learn more:\n\n- [@official@Packages and Plugins](https://docs.flutter.dev/development/packages-and-plugins)\n- [@video@Dart Package Manager (pub.dev) in Flutter](https://www.youtube.com/watch?v=F1VRO0_MKLs)', 8, '2025-08-28 09:42:01', '2026-04-05 14:42:29'),
	(9, 1, 'Working With Apis', '9Az7tmevGI6bVqCTvVL50', '# Working with APIs\n\nWorking with APIs in Flutter involves making HTTP requests to a server and processing the responses. Flutter provides a number of libraries for making HTTP requests, including `dart:io` and `http`.\n\nThe `http` library is a popular choice for making HTTP requests in Flutter, as it is easy to use and provides support for HTTP methods such as GET, POST, PUT, DELETE, and more.\n\nVisit the following resources to learn more:\n\n- [@article@Using Google APIs](https://dart.dev/guides/google-apis)\n- [@video@How to work with APIs in Flutter?](https://www.youtube.com/watch?v=uVo7HDWDUEQ)', 9, '2025-08-28 09:42:01', '2026-04-05 14:42:30'),
	(10, 1, 'Storage', 'P_wptV7oenaYwef1QhKhu', '# Storage\n\nFlutter provides several options for persistent storage, some of which are as follow:\n\n*   SharedPreferences: A key-value store for small data.\n*   SQLite database: A relational database for structured data.\n*   File System: For storing large files and data.\n*   Firebase: A real-time database and backend as a service.\n\nAll of these storage options are supported through third-party packages, which are easily integrated into a Flutter app.\n\nVisit the following resources to learn more:\n\n- [@official@Cloud Storage in Flutter](https://firebase.flutter.dev/docs/storage/overview/)\n- [@video@Storage - Flutter Tutorial](https://www.youtube.com/watch?v=UpKrhZ0Hppks)\n- [@feed@Explore top posts about Storage](https://app.daily.dev/tags/storage?ref=roadmapsh)', 10, '2025-08-28 09:42:02', '2026-04-05 14:42:30'),
	(11, 1, 'Advanced Dart', 'bvojoCWJRSB6pdBFM1SbY', '# Advanced Dart\n\nAdvanced Dart concepts crucial for Flutter development include generics for reusable code, `async`/`await` for clean asynchronous operations, mixins for multiple inheritance, abstract classes for base implementations, streams for continuous event handling, isolates for parallel processing, futures for future value representation, null-aware operators for concise null handling, collection literals for efficient collection creation, and extension methods for adding functionality to existing classes, all contributing to more efficient and maintainable code.\n\nVisit the following resources to learn more:\n\n- [@official@Tutorials - Dart](https://dart.dev/tutorials)\n- [@article@Advanced Dart](https://techdynasty.medium.com/advanced-dart-in-flutter-elevating-your-development-skills-1c8ec309266f)\n- [@feed@Explore top posts about Dart](https://app.daily.dev/tags/dart?ref=roadmapsh)', 11, '2025-08-28 09:42:02', '2026-04-05 14:42:31'),
	(12, 1, 'State Management', 'bYJ0G-g4R5faoJfFjRQW7', '# State Management\n\nState management in Flutter refers to the process of managing and updating the data or state of a Flutter application. In Flutter, the state of the widgets can change dynamically, for example, when a user interacts with the application.\n\nVisit the following resources to learn more:\n\n- [@official@State Management in Flutter](https://docs.flutter.dev/development/data-and-backend/state-mgmt)', 12, '2025-08-28 09:42:02', '2026-04-05 14:42:31'),
	(13, 1, 'Reactive Programming', 'wbush8eQsi9aDSRobGAyG', '# Reactive Programming\n\nReactive programming is a programming paradigm that allows for handling changing data streams and updating the UI based on those changes.\n\nReactive programming in Flutter helps create dynamic and responsive apps that can handle changing data and update the UI accordingly. The `StreamBuilder` and `FutureBuilder` widgets are commonly used in Flutter to build reactive UIs.\n\nVisit the following resources to learn more:\n\n- [@article@Get Started with Reactive Programming](https://www.didierboelens.com/2018/12/reactive-programming-streams-bloc-practical-use-cases/)\n- [@video@Reactive Programming in Flutter](https://www.youtube.com/watch?v=x4FKXw4Uvls)\n- [@feed@Explore top posts about Reactive Programming](https://app.daily.dev/tags/reactive-programming?ref=roadmapsh)', 13, '2025-08-28 09:42:02', '2026-04-05 14:42:31'),
	(14, 1, 'Animations', 'KLoL-055KShGrQ-NQosy8', '# Animations\n\nFlutter’s animation support makes it easy to implement a variety of animation types. Many widgets, especially Material widgets, come with the standard motion effects defined in their design spec, but it’s also possible to customize these effects.\n\nVisit the following resources to learn more:\n\n- [@official@Introduction to Animations](https://docs.flutter.dev/development/ui/animations)\n- [@article@Animation library](https://api.flutter.dev/flutter/animation/animation-library.html)', 14, '2025-08-28 09:42:02', '2026-04-05 14:42:32'),
	(15, 1, 'Testing', 'zGkDu5j8ln8U9kZgz3TDJ', '# Testing\n\nTesting is a crucial part of the development process in Flutter, as it helps you to verify the behavior and appearance of your app and ensure that it behaves correctly and consistently across different devices and platforms.\n\nVisit the following resources to learn more:\n\n- [@official@Dart Testing](https://dart.dev/guides/testing)\n- [@official@Testing Flutter Apps](https://docs.flutter.dev/testing)\n- [@feed@Explore top posts about Testing](https://app.daily.dev/tags/testing?ref=roadmapsh)', 15, '2025-08-28 09:42:02', '2026-04-05 14:42:32'),
	(16, 1, 'Dev Tools', 'Jti4RmGDn7jVaHOxtTwPc', '# Dev Tools\n\nFlutter DevTools is a suite of development tools provided by Flutter to help developers build, test, and debug Flutter apps.\n\nVisit the following resources to learn more:\n\n- [@official@Flutter - DevTools](https://docs.flutter.dev/development/tools/devtools/overview)\n- [@official@Dart DevTools](https://dart.dev/tools/dart-devtools)\n- [@feed@Explore top posts about Tools](https://app.daily.dev/tags/tools?ref=roadmapsh)', 16, '2025-08-28 09:42:02', '2026-04-05 14:42:33'),
	(17, 1, 'Flutter Internals', 'dgdv8sDKkgQ365mR0kBR3', '# Flutter Internals\n\nThe internal workings of Flutter refer to the underlying mechanisms and architecture that make up the Flutter framework. Flutter is a reactive framework for building user interfaces, which means that it allows developers to build dynamic, responsive apps that update automatically in response to changes in the state of the app.\n\nVisit the following resources to learn more:\n\n- [@article@Flutter - Internals](https://www.didierboelens.com/2019/09/flutter-internals/)\n- [@article@Overview of Flutter Internals](https://flutter.megathink.com/)\n- [@article@A Guide To Flutter Internals](https://medium.com/@subroto.2003/a-guide-to-flutter-internals-ce8d64d01c50)\n- [@video@Flutter and Dart | Widget & Flutter Internals](https://www.youtube.com/watch?v=FBXMvOmiOLE)\n- [@feed@Explore top posts about Flutter](https://app.daily.dev/tags/flutter?ref=roadmapsh)', 17, '2025-08-28 09:42:02', '2026-04-05 14:42:33'),
	(18, 1, 'Ci Cd', 'ekKzwQCMOYJLVN5KAK-ew', '# CI/CD\n\nCI/CD (Continuous Integration and Continuous Deployment) is a software development practice that helps to automate the process of building, testing, and deploying mobile apps, including Flutter apps.\n\nWith CI/CD, developers can automate the build, test, and deployment process for their Flutter apps, making it easier to catch bugs and deploy new features quickly and efficiently.\n\nVisit the following resources to learn more:\n\n- [@official@CI/CD - Flutter](https://docs.flutter.dev/deployment/cd)\n- [@feed@Explore top posts about CI/CD](https://app.daily.dev/tags/cicd?ref=roadmapsh)', 18, '2025-08-28 09:42:02', '2026-04-05 14:42:34'),
	(19, 1, 'Analytics', 's5OVzjQp6k7rSphhv3hZE', '# Analytics\n\nAnalytics is a key aspect of understanding user behavior and measuring app performance for Flutter apps. There are a number of analytics tools available for Flutter apps, each with their own set of features and benefits.\n\nVisit the following resources to learn more:\n\n- [@article@Top Flutter Analytics](https://fluttergems.dev/analytics-consumer-insights/)\n- [@video@Flutter Analytics using Firebase](https://www.youtube.com/watch?v=31KpJXqCayo)', 19, '2025-08-28 09:42:02', '2026-04-05 14:42:34'),
	(20, 1, 'Deployment', 'mdSWrWi-1n_YlY5iTJwZp', '# Deployment\n\nDeployment in Flutter refers to the process of releasing a Flutter app to end-users. Deploying a Flutter app involves a combination of technical skills and experience, as well as knowledge of the relevant app stores and their policies and requirements.\n\nVisit the following resources to learn more:\n\n- [@official@Web Deployment](https://dart.dev/web/deployment)\n- [@feed@Explore top posts about CI/CD](https://app.daily.dev/tags/cicd?ref=roadmapsh)', 20, '2025-08-28 09:42:02', '2026-04-05 14:42:35');
